import React, { useState, useContext } from 'react';
import { Link } from 'react-router-dom';
import { SessionContext } from '../context/SessionContext.js';
import LoadingSpinner from '../components/common/LoadingSpinner';

function Dashboard() {
  const [goal, setGoal] = useState('');
  const [formError, setFormError] = useState(null);

  const { 
    history, 
    startNewSession, 
    loadSession, // Use loadSession to resume a past session
    loading: contextLoading, 
    error: contextError 
  } = useContext(SessionContext);

  const handleStartSession = async (e) => {
    e.preventDefault();
    if (!goal.trim() || contextLoading) return;

    setFormError(null);

    try {
      await startNewSession(goal);
      // Navigation is now handled by the context based on the new session's stage
    } catch (err) { 
      console.error("Failed to create session: ", err);
      setFormError('Failed to start a new session. Please try again.');
    }
  };

  const handleResumeSession = (sessionId) => {
    loadSession(sessionId);
    // Navigation is handled by the context
  };

  const getStatusColor = (status) => {
    // This remains a presentational helper
    switch (status) {
      case 'completed': return 'bg-green-100 text-green-800';
      case 'running': return 'bg-blue-100 text-blue-800';
      case 'new': return 'bg-gray-100 text-gray-800';
      default: return 'bg-yellow-100 text-yellow-800';
    }
  };

  return (
    <div className="container mx-auto p-8">
        <div className="max-w-4xl mx-auto">
            <div className="text-center mb-12">
                <h1 className="text-5xl font-extrabold text-gray-900 mb-4">QuantumFlow</h1>
                <p className="text-xl text-gray-600">Your AI-Guided Path from Problem to Quantum-Ready Solution.</p>
            </div>

            <div className="bg-white p-6 rounded-xl shadow-lg mb-12">
                <form onSubmit={handleStartSession}>
                    <label htmlFor="goal-input" className="block text-lg font-medium text-gray-800 mb-2">Start a New Analysis</label>
                    <div className="flex gap-4">
                        <input
                            id="goal-input"
                            type="text"
                            value={goal}
                            onChange={(e) => setGoal(e.target.value)}
                            placeholder="E.g., 'Optimize my logistics network for faster delivery times'"
                            className="flex-grow p-4 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 transition"
                            disabled={contextLoading}
                        />
                        <button 
                            type="submit" 
                            className="bg-blue-600 text-white font-bold py-3 px-6 rounded-lg hover:bg-blue-700 transition transform hover:scale-105 disabled:bg-gray-400 disabled:scale-100"
                            disabled={!goal.trim() || contextLoading}
                        >
                            {contextLoading ? 'Starting...' : 'Start Session'}
                        </button>
                    </div>
                </form>
                 {formError && <p className="text-red-500 mt-4 text-center">{formError}</p>}
            </div>

            <div>
                <h2 className="text-2xl font-bold text-gray-800 mb-6">Recent Sessions</h2>
                {contextLoading && !history.length ? (
                    <LoadingSpinner text="Loading recent sessions..." />
                ) : contextError ? (
                    <p className="text-center text-red-500 bg-red-50 p-8 rounded-lg">{`Error loading history: ${contextError.message}`}</p>
                ) : history.length > 0 ? (
                    <div className="space-y-4">
                        {history.map((session) => (
                            <div 
                                key={session.id}
                                onClick={() => handleResumeSession(session.id)}
                                className="block bg-white p-5 rounded-lg shadow-md hover:shadow-xl transition-shadow border border-gray-200 cursor-pointer"
                            >
                                <div className="flex justify-between items-center">
                                    <div>
                                        <p className="font-semibold text-lg text-gray-800">{session.goal || 'Untitled Session'}</p>
                                        <p className="text-sm text-gray-500">{`ID: ${session.id}`}</p>
                                    </div>
                                    <div className="text-right">
                                        <span className={`px-3 py-1 text-sm font-semibold rounded-full ${getStatusColor(session.status)}`}>
                                            {session.status}
                                        </span>
                                        <p className="text-xs text-gray-400 mt-1">{session.createdAt?.toDate ? session.createdAt.toDate().toLocaleDateString() : 'N/A'}</p>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                ) : (
                    <p className="text-center text-gray-500 bg-gray-50 p-8 rounded-lg">No recent sessions found. Start a new analysis to begin.</p>
                )}
            </div>
        </div>
    </div>
  );
}

export default Dashboard;
